  1→"use client";
  2→
  3→import { useEffect, useState, useCallback } from "react";
  4→import { useRouter } from "next/navigation";
  5→import Header from "@/components/Header";
  6→import StatsCards from "@/components/StatsCards";
  7→import RatingDistribution from "@/components/RatingDistribution";
  8→import SentimentChart from "@/components/SentimentChart";
  9→import KeywordsCloud from "@/components/KeywordsCloud";
 10→import ReviewCard from "@/components/ReviewCard";
 11→import ChatDrawer from "@/components/ChatDrawer";
 12→import { Review, ReviewMetadata, AnalyticsData } from "@/types";
 13→import { MessageSquare } from "lucide-react";
 14→
 15→export default function DashboardPage() {
 16→  const router = useRouter();
 17→  const [reviews, setReviews] = useState<Review[]>([]);
 18→  const [metadata, setMetadata] = useState<ReviewMetadata | null>(null);
 19→  const [analytics, setAnalytics] = useState<AnalyticsData | null>(null);
 20→  const [loading, setLoading] = useState(true);
 21→  const [showAllReviews, setShowAllReviews] = useState(false);
 22→  const [chatOpen, setChatOpen] = useState(false);
 23→  const [sessionId, setSessionId] = useState<string | null>(null);
 24→  const closeChat = useCallback(() => setChatOpen(false), []);
 25→
 26→  useEffect(() => {
 27→    const sid = sessionStorage.getItem("reviewlens_session");
 28→    const metaStr = sessionStorage.getItem("reviewlens_metadata");
 29→    const reviewsStr = sessionStorage.getItem("reviewlens_reviews");
 30→    const analyticsStr = sessionStorage.getItem("reviewlens_analytics");
 31→
 32→    if (!sid || !metaStr || !reviewsStr || !analyticsStr) {
 33→      router.push("/");
 34→      return;
 35→    }
 36→
 37→    try {
 38→      setSessionId(sid);
 39→      setMetadata(JSON.parse(metaStr));
 40→      setReviews(JSON.parse(reviewsStr));
 41→      setAnalytics(JSON.parse(analyticsStr));
 42→    } catch {
 43→      router.push("/");
 44→      return;
 45→    }
 46→    setLoading(false);
 47→  }, [router]);
 48→
 49→  if (loading) {
 50→    return (
 51→      <>
 52→        <Header />
 53→        <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
 54→          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
 55→            {Array.from({ length: 4 }).map((_, i) => (
 56→              <div key={i} className="glass-card rounded-xl h-24 animate-pulse" />
 57→            ))}
 58→          </div>
 59→          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
 60→            <div className="glass-card rounded-xl h-72 animate-pulse" />
 61→            <div className="glass-card rounded-xl h-72 animate-pulse" />
 62→          </div>
 63→        </main>
 64→      </>
 65→    );
 66→  }
 67→
 68→  if (!metadata || !analytics) return null;
 69→
 70→  const displayedReviews = showAllReviews ? reviews : reviews.slice(0, 6);
 71→
 72→  return (
 73→    <>
 74→      <Header />
 75→      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
 76→        {/* Page header */}
 77→        <div className="flex items-center justify-between mb-8 animate-fade-up">
 78→          <div>
 79→            <h1 className="text-2xl sm:text-3xl font-bold text-white/90">
 80→              {metadata.productName}
 81→            </h1>
 82→            <p className="text-sm text-white/40 mt-1">
 83→              {metadata.platform} &middot; {metadata.totalReviews} reviews analyzed &middot;
 84→              Scraped {new Date(metadata.scrapedAt).toLocaleDateString()}
 85→            </p>
 86→          </div>
 87→          <button
 88→            onClick={() => setChatOpen(true)}
 89→            className="gradient-btn text-white font-medium py-2.5 px-5 rounded-xl flex items-center gap-2 text-sm"
 90→          >
 91→            <MessageSquare className="w-4 h-4" />
 92→            Ask Questions
 93→          </button>
 94→        </div>
 95→
 96→        {/* Stats */}
 97→        <div className="mb-8">
 98→          <StatsCards metadata={metadata} analytics={analytics} />
 99→        </div>
100→
101→        {/* Charts */}
102→        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
103→          <div className="animate-fade-up delay-200" style={{ animationFillMode: 'backwards' }}>
104→            <RatingDistribution distribution={analytics.ratingDistribution} />
105→          </div>
106→          <div className="animate-fade-up delay-300" style={{ animationFillMode: 'backwards' }}>
107→            <SentimentChart breakdown={analytics.sentimentBreakdown} />
108→          </div>
109→        </div>
110→
111→        {/* Keywords */}
112→        {analytics.topKeywords.length > 0 && (
113→          <div className="mb-8 animate-fade-up delay-400" style={{ animationFillMode: 'backwards' }}>
114→            <KeywordsCloud keywords={analytics.topKeywords} />
115→          </div>
116→        )}
117→
118→        {/* Reviews */}
119→        <div className="mb-8">
120→          <div className="flex items-center justify-between mb-4">
121→            <h2 className="text-lg font-semibold text-white/80">Reviews</h2>
122→            {reviews.length > 6 && (
123→              <button
124→                onClick={() => setShowAllReviews(!showAllReviews)}
125→                className="text-sm text-violet-400 hover:text-violet-300 transition-colors"
126→              >
127→                {showAllReviews ? "Show Less" : `Show All (${reviews.length})`}
128→              </button>
129→            )}
130→          </div>
131→          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
132→            {displayedReviews.map((review, i) => (
133→              <ReviewCard key={review.id} review={review} index={i} />
134→            ))}
135→          </div>
136→        </div>
137→      </main>
138→
139→      {/* Floating chat button */}
140→      {!chatOpen && (
141→        <button
142→          onClick={() => setChatOpen(true)}
143→          className="fixed! bottom-8 right-8 w-14 h-14 rounded-full text-white shadow-xl shadow-violet-500/25 flex items-center justify-center z-40 hover:scale-105 transition-transform"
144→          style={{ background: "linear-gradient(135deg, #8b5cf6, #6366f1)" }}
145→        >
146→          <MessageSquare className="w-6 h-6" />
147→        </button>
148→      )}
149→
150→      {/* Chat drawer */}
151→      {sessionId && metadata && (
152→        <ChatDrawer
153→          open={chatOpen}
154→          onClose={closeChat}
155→          sessionId={sessionId}
156→          metadata={metadata}
157→        />
158→      )}
159→    </>
160→  );
161→}
